#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)b - *(int*)a);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int scores[11];
        for (int i = 0; i < 11; i++) {
            scanf("%d", &scores[i]);
        }
        int K;
        scanf("%d", &K);
        qsort(scores, 11, sizeof(int), compare);
        int max_sum = 0;
        for (int i = 0; i < K; i++) {
            max_sum += scores[i];
        }
        int count = 0;
        for (int mask = 0; mask < (1 << 11); mask++) {
            int sum = 0;
            int bits = 0;
            for (int i = 0; i < 11; i++) {
                if ((mask & (1 << i)) != 0) {
                    sum += scores[i];
                    bits++;
                }
            }
            if (bits == K && sum == max_sum) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

